{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式キックオフし、正式発足する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00から1時間で開催し、各部署から少なくとも1名参加、リモート参加可とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行はマスタデータを先行移行し、トランザクションデータは第2フェーズ以降に回して旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証・マスタ基盤はサクラ商事さんとの共同利用で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行方式は拠点を複数グループに分けて段階的に切り替える段階移行とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリース目標日は2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "新システムでは既存のロール定義を流用し、権限の再設計は稼働後の運用改善として扱う。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D8",
      "content": "障害の一次受け窓口はQAチームとし、一次切り分けまでをQAが担当する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "負荷テストと移行テストはシステムテストと分けて実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "移行リハーサルの手順書作成担当を沼田 賢一に変更する。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "現場ヒアリングの対象部署リストを表形式で作成し、想定窓口の氏名も含めて提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A2",
